  2040→            if (expiretime != -1) setExpire(NULL,db,key,expiretime);
  2041→
  2042→            /* Set usage information (for eviction). */
  2043→            objectSetLRUOrLFU(val,lfu_freq,lru_idle,lru_clock);
  2044→
  2045→            /* Decrement the key refcount since dbAdd() will take its
